  "email or name": { ja: "メールアドレスまたは名前", es: "correo electrónico o nombre" },
  "Enable models for parallel compare. Provider keys stay server-side.": { ja: "モデルの並列比較を有効にします。プロバイダーキーはサーバー側に残ります。", es: "Habilite modelos para comparación paralela. Las claves del proveedor permanecen en el lado del servidor." },
