  "Template step ": { ja: "テンプレートステップ", es: "Paso de plantilla" },
  "Text files (.txt, .md, .csv), JSON, Word documents (.docx), PDF documents, and images (.png, .jpg, .webp, .gif). Files are processed server-side and included in prompts for all models.": { ja: "テキスト ファイル (.txt、.md、.csv)、JSON、Word ドキュメント (.docx)、PDF ドキュメント、および画像 (.png、.jpg、.webp、.gif)。ファイルはサーバー側で処理され、すべてのモデルのプロンプトに含まれます。", es: "Archivos de texto (.txt, .md, .csv), JSON, documentos de Word (.docx), documentos PDF e imágenes (.png, .jpg, .webp, .gif). Los archivos se procesan en el lado del servidor y se incluyen en las solicitudes de todos los modelos." },
  "The browser blocked automatic copying of the original input.": { ja: "ブラウザーは、元の入力の自動コピーをブロックしました。", es: "El navegador bloqueó la copia automática de la entrada original." },
